## 3. JavaScript Parallax Implementation

**File:** `/Users/jbiggs/code/buy-hh/buy-honehealth-com/themes/HoneLandingPages/src/static/js/pages/womens-hormone-imbalance.bundle.js` (lines 265-343)

```javascript
/**
 * =============================
 * PARALLAX MARQUEE EFFECT
 * =============================
 */

function initMarqueeParallax() {
	const monitorSection = document.querySelector('.monitor-for-early-indicators');
	const diseaseRows = document.querySelectorAll('.monitor-for-early-indicators .disease-row-list');

	if (!monitorSection || diseaseRows.length === 0) {
		return;
	}

	let ticking = false;

	function updateMarqueeParallax() {
		const rect = monitorSection.getBoundingClientRect();
		const viewportHeight = window.innerHeight;
		const sectionHeight = rect.height;

		if (rect.top <= viewportHeight && rect.bottom >= 0) {
			const startPoint = viewportHeight;
			const endPoint = -sectionHeight;
			const currentPosition = rect.top;

			const totalDistance = startPoint - endPoint;
			const currentDistance = startPoint - currentPosition;
			const progress = Math.max(0, Math.min(1, currentDistance / totalDistance));

			diseaseRows.forEach((row, index) => {
				const scrollWidth = row.scrollWidth / 2;
				const maxOffset = scrollWidth;

				let speed, direction;
				switch (index) {
					case 0:
						speed = 0.125;
						direction = 1;
						break;
					case 1:
						speed = 0.15;
						direction = -1;
						break;
					case 2:
						speed = 0.1;
						direction = 1;
						break;
					default:
						speed = 0.1;
						direction = 1;
				}

				const baseOffset = progress * maxOffset * speed * direction;
				const offset = ((baseOffset % maxOffset) + maxOffset) % maxOffset;

				if (direction === 1) {
					row.style.transform = `translateX(-${offset}px)`;
				} else {
					row.style.transform = `translateX(${offset - maxOffset}px)`;
				}
			});
		}

		ticking = false;
	}

	function requestTick() {
		if (!ticking) {
			requestAnimationFrame(updateMarqueeParallax);
			ticking = true;
		}
	}

	window.addEventListener('scroll', requestTick, { passive: true });
	window.addEventListener('resize', requestTick, { passive: true });

	updateMarqueeParallax();
}
